    @Test
    fun testCallbackFlowCloseWithExceptionDirectTimeout() = runTest {
        val flow = callbackFlow<Int> {
            close(IllegalStateException("Test Exception"))
        }.timeout(5.seconds)

        val exception = assertFailsWith<IllegalStateException> {
            flow.collect()
        }
        assertEquals("Test Exception", exception.message)
        finish(1)
    }

    @Test
    fun testCallbackFlowCloseWithExceptionAfterEmitDirectTimeout() = runTest {
        val flow = callbackFlow<Int> {
            send(1)
            send(2)
            close(IllegalStateException("Test Exception After Emit"))
        }.timeout(5.seconds)

        val collected = mutableListOf<Int>()
        val exception = assertFailsWith<IllegalStateException> {
            flow.collect { collected.add(it) }
        }
        assertEquals(listOf(1, 2), collected)
        assertEquals("Test Exception After Emit", exception.message)
        finish(1)
    }

    @Test
    fun testCallbackFlowNormalCloseDirectTimeout() = runTest {
        val flow = callbackFlow<Int> {
            send(1)
            send(2)
            close()
        }.timeout(5.seconds)

