import kotlinx.coroutines.*
import kotlinx.coroutines.flow.*
import kotlin.test.*
import kotlin.time.Duration.Companion.seconds

class TimeoutCallbackFlowTest : TestBase() {

    @Test
    fun testCallbackFlowCloseWithExceptionDirectTimeout() = runTest {
        val flow = callbackFlow<Int> {
            close(IllegalStateException("Test Exception"))
        }.timeout(5.seconds)

        val exception = assertFailsWith<IllegalStateException> {
            flow.collect()
        }
        assertEquals("Test Exception", exception.message)
        finish(1)
    }

    @Test
    fun testCallbackFlowCloseWithExceptionAfterEmitDirectTimeout() = runTest {
        val flow = callbackFlow<Int> {
            send(1)
            send(2)
            close(IllegalStateException("Test Exception After Emit"))
        }.timeout(5.seconds)

        val collected = mutableListOf<Int>()
        val exception = assertFailsWith<IllegalStateException> {
            flow.collect { collected.add(it) }
        }
        assertEquals(listOf(1, 2), collected)
        assertEquals("Test Exception After Emit", exception.message)
        finish(1)
    }

    @Test
    fun testCallbackFlowNormalCloseDirectTimeout() = runTest {
        val flow = callbackFlow<Int> {
            send(1)
            send(2)
            close()
        }.timeout(5.seconds)

        val collected = flow.toList()
        assertEquals(listOf(1, 2), collected)
        finish(1)
    }

    @Test
    fun testCallbackFlowCloseWithExceptionWithIntermediateOperator() = runTest {
        // This was the workaround mentioned in the issue - should still work
        val flow = callbackFlow<Int> {
            close(IllegalStateException("Test Exception With Operator"))
        }.catch { throw it }.timeout(5.seconds)

        val exception = assertFailsWith<IllegalStateException> {
            flow.collect()
        }
        assertEquals("Test Exception With Operator", exception.message)
        finish(1)
    }

    @Test
    fun testCallbackFlowCloseWithCancellationExceptionDirectTimeout() = runTest {
        val flow = callbackFlow<Int> {
            close(CancellationException("Cancelled"))
        }.timeout(5.seconds)

        val exception = assertFailsWith<CancellationException> {
            flow.collect()
        }
        assertEquals("Cancelled", exception.message)
        finish(1)
    }

    @Test
    fun testCallbackFlowCloseWithCustomExceptionDirectTimeout() = runTest {
        class CustomException(message: String) : Exception(message)

        val flow = callbackFlow<Int> {
            close(CustomException("Custom Error"))
        }.timeout(5.seconds)

        val exception = assertFailsWith<CustomException> {
            flow.collect()
        }
        assertEquals("Custom Error", exception.message)
        finish(1)
    }
}
